/**
 * @fileoverview TreeView events — centralised event binding via AbortController.
 * @module module/TreeView/events
 */

import razyui from '../../index.js';
import { CLS, DEFAULTS } from './constants.js';

/**
 * Bind core event listeners (click, dblclick, keydown) on the container.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLElement} container
 * @param {object} config — { editable }
 * @param {object} handlers — { onRowClick, onToggleClick, onLabelDblClick, onKeydown }
 * @returns {AbortController}
 */
export function bindEvents(container, config, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $container = razyui(container);

    // Click: select + toggle
    $container.on('click', (e) => {
        // Skip action buttons and checkboxes — handled by bindNodeActions
        const target = razyui(e.target);
        if (target.closest('.' + CLS.ACTION_BTN).length || target.closest('input.' + CLS.CHECKBOX).length) return;

        const row = target.closest('.' + CLS.ROW);
        if (!row.length) return;

        const nodeEl = row.closest('.' + CLS.NODE);
        const id = nodeEl.attr('data-id');
        if (!id) return;

        // Toggle arrow click
        if (target.closest('.' + CLS.TOGGLE + '.' + CLS.HAS_CHILDREN).length) {
            handlers.onToggleClick(id);
            return;
        }

        // Select
        handlers.onRowClick(id);
    }, opts);

    // Double-click: inline edit
    if (config.editable) {
        $container.on('dblclick', (e) => {
            const label = razyui(e.target).closest('.' + CLS.LABEL);
            if (!label.length) return;
            const nodeEl = label.closest('.' + CLS.NODE);
            if (nodeEl.length) handlers.onLabelDblClick(nodeEl.attr('data-id'), label[0]);
        }, opts);
    }

    // Keyboard
    $container.on('keydown', (e) => handlers.onKeydown(e), opts);

    return ac;
}

/**
 * Bind drag-and-drop event listeners on the container.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLElement} container
 * @param {object} handlers — { isDescendant, moveNode, getNode }
 * @returns {AbortController}
 */
export function bindDragDrop(container, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const $container = razyui(container);
    let dragId = null;

    // Create reusable drop indicator
    const dropIndicator = razyui.el('div', { className: CLS.DROP_INDICATOR });
    dropIndicator.css('display', 'none');

    $container.on('dragstart', (e) => {
        const nodeEl = razyui(e.target).closest('.' + CLS.NODE);
        if (!nodeEl.length) return;
        dragId = nodeEl.attr('data-id');
        nodeEl.addClass(CLS.DRAGGING);
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', dragId);
    }, opts);

    $container.on('dragend', () => {
        dragId = null;
        $container.find('.' + CLS.DRAGGING).removeClass(CLS.DRAGGING);
        $container.find('.' + CLS.ROW).removeClass(CLS.DROP_BEFORE + ' ' + CLS.DROP_AFTER + ' ' + CLS.DROP_INSIDE);
        dropIndicator.css('display', 'none');
    }, opts);

    $container.on('dragover', (e) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';

        const row = razyui(e.target).closest('.' + CLS.ROW);
        if (!row.length) return;

        const nodeEl = row.closest('.' + CLS.NODE);
        const targetId = nodeEl.attr('data-id');
        if (!targetId || targetId === dragId) return;

        // Don't drop onto own descendants
        if (handlers.isDescendant(dragId, targetId)) return;

        // Clear previous indicators
        $container.find('.' + CLS.ROW).removeClass(CLS.DROP_BEFORE + ' ' + CLS.DROP_AFTER + ' ' + CLS.DROP_INSIDE);

        // Determine drop zone (top 25% = before, bottom 25% = after, middle = inside)
        const rect = row.getRect();
        const y = e.clientY - rect.top;
        const h = rect.height;

        if (y < h * DEFAULTS.dropZoneRatio) {
            row.addClass(CLS.DROP_BEFORE);
        } else if (y > h * (1 - DEFAULTS.dropZoneRatio)) {
            row.addClass(CLS.DROP_AFTER);
        } else {
            // Prevent drop-inside when target node disallows children
            const targetNode = handlers.getNode?.(targetId);
            if (targetNode && targetNode.allowChildren === false) {
                row.addClass(CLS.DROP_AFTER);
            } else {
                row.addClass(CLS.DROP_INSIDE);
            }
        }
    }, opts);

    $container.on('dragleave', (e) => {
        const row = razyui(e.target).closest('.' + CLS.ROW);
        if (row.length) {
            row.removeClass(CLS.DROP_BEFORE + ' ' + CLS.DROP_AFTER + ' ' + CLS.DROP_INSIDE);
        }
    }, opts);

    $container.on('drop', (e) => {
        e.preventDefault();

        const row = razyui(e.target).closest('.' + CLS.ROW);
        if (!row.length) return;

        const nodeEl = row.closest('.' + CLS.NODE);
        const targetId = nodeEl.attr('data-id');
        if (!targetId || !dragId || targetId === dragId) return;
        if (handlers.isDescendant(dragId, targetId)) return;

        // Determine position
        const rect = row.getBoundingClientRect();
        const y = e.clientY - rect.top;
        const h = rect.height;
        let position;
        if (y < h * DEFAULTS.dropZoneRatio) {
            position = 'before';
        } else if (y > h * (1 - DEFAULTS.dropZoneRatio)) {
            position = 'after';
        } else {
            // Prevent drop-inside when target node disallows children
            const targetNode = handlers.getNode?.(targetId);
            position = (targetNode && targetNode.allowChildren === false) ? 'after' : 'inside';
        }

        handlers.moveNode(dragId, targetId, position);

        // Clear
        $container.find('.' + CLS.ROW).removeClass(CLS.DROP_BEFORE + ' ' + CLS.DROP_AFTER + ' ' + CLS.DROP_INSIDE);

        dragId = null;
    }, opts);

    return ac;
}

/**
 * Bind delegated node-action listeners (checkbox, add, delete) on the container.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLElement} container
 * @param {object} handlers — { onToggleCheck, onAddChild, onDeleteNode }
 * @returns {AbortController}
 */
export function bindNodeActions(container, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $container = razyui(container);

    // Checkbox change (delegated)
    $container.on('change', (e) => {
        const cb = razyui(e.target).closest('input.' + CLS.CHECKBOX);
        if (!cb.length) return;
        const nodeEl = cb.closest('.' + CLS.NODE);
        const id = nodeEl.attr('data-id');
        if (id) handlers.onToggleCheck(id, cb[0].checked);
    }, opts);

    // Add / Delete button clicks (delegated)
    $container.on('click', (e) => {
        const actionBtn = razyui(e.target).closest('.' + CLS.ACTION_BTN);
        if (!actionBtn.length) return;

        const nodeEl = actionBtn.closest('.' + CLS.NODE);
        const id = nodeEl.attr('data-id');
        if (!id) return;

        if (actionBtn.hasClass(CLS.ACTION_DELETE)) {
            handlers.onDeleteNode(id);
        } else {
            handlers.onAddChild(id);
        }
    }, opts);

    return ac;
}
