/**
 * @fileoverview TreeView component definition for JIT pipeline.
 *
 * @module module/TreeView.def
 */

import razyui from '../index.js';import { PART } from './TreeView/constants.js';
/**
 * The definition object for the TreeView component.
 * Contains metadata, tokens, states, templates, variants, and attribute mappings.
 *
 * @type {Object}
 */
export const TreeViewDef = {
    name: 'TreeView',
    tag: 'rui-tree-view',

    tokens: {
        prefix: 'tv',
        tokens: {
            'radius':          { ref: 'radius.md',           description: 'Container border radius' },
            'row-radius':      { ref: 'radius.sm',           description: 'Row border radius' },
            'font-size':       { ref: 'font.size-sm',        description: 'Font size' },
            'line-height':     { value: '1.25',              description: 'Line height' },
            'font-stack':      { ref: 'font.family',         description: 'Font family' },
            'accent':          { ref: 'color.accent',        description: 'Accent / selected color' },
            'accent-subtle':   { ref: 'color.accent-subtle', description: 'Focus ring color' },
            'bg':              { ref: 'color.bg',            description: 'Background' },
            'bg-hover':        { ref: 'color.bg-hover',      description: 'Hover background' },
            'bg-inset':        { ref: 'color.bg-inset',      description: 'Inset background' },
            'border':          { ref: 'color.border',        description: 'Border color' },
            'danger':          { ref: 'color.danger',        description: 'Danger/error color' },
            'indent':          { value: '1.25rem',           description: 'Indentation per level' },
            'row-gap':         { ref: 'spacing.1',           description: 'Gap between rows' },
            'row-py':          { ref: 'spacing.1',           description: 'Row vertical padding' },
            'row-px':          { ref: 'spacing.2',           description: 'Row horizontal padding' },
            'row-height':      { value: '2rem',               description: 'Row height' },
            'shadow':          { ref: 'shadow.sm',           description: 'Drop indicator shadow' },
            'text':            { ref: 'color.text',          description: 'Text color' },
            'text-muted':      { ref: 'color.text-muted',    description: 'Muted text' },
            'z-index':         { value: '10',                description: 'Drag overlay z-index' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle:     { on: { DRAG_START: 'dragging' } },
            dragging: { on: { DRAG_END: 'idle', DROP: 'idle' } },
        },
        effects: {
            dragging(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-dragging');
            },
            'dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-dragging');
            },
        },
    },

    template: {
        slots: {
            root:      { element: 'div', classes: ['tree-view'] },
            node:      { element: 'div', classes: ['tree-view-node'] },
            row:       { element: 'div', classes: ['tree-view-row'] },
            icon:      { element: 'span', classes: ['tree-view-icon'] },
            label:     { element: 'span', classes: ['tree-view-label'] },
            children:  { element: 'div', classes: ['tree-view-children'] },
            toggle:    { element: 'button', classes: ['tree-view-toggle'] },
        },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.NODE]: PART.NODE,
        [PART.ROW]: PART.ROW,
        [PART.TOGGLE]: PART.TOGGLE,
        [PART.LABEL]: PART.LABEL,
        [PART.ACTIONS]: PART.ACTIONS,
        [PART.ACTION_BTN]: PART.ACTION_BTN,
        [PART.CHECKBOX]: PART.CHECKBOX,
        [PART.ICON]: PART.ICON,
        [PART.CHILDREN]: PART.CHILDREN,
        [PART.EDIT_INPUT]: PART.EDIT_INPUT,
    },

    styles: {},

    observedAttrs: ['data', 'selected', 'draggable'],
    attrMap: {
        data: 'data',
        selected: 'selected',
        draggable: 'draggable',
    },
};

export default TreeViewDef;
